function candidate(input, options) {
  const config = options || {};
  const delimiter = config.delimiter === undefined ? '&' : config.delimiter;
  const limit = config.parameterLimit === undefined ? 1000 : config.parameterLimit;
  const strictNull = config.strictNullHandling === true;
  const useSentinel = config.charsetSentinel === true;
  const numericEntities = config.interpretNumericEntities === true;
  const commaArrays = config.comma === true;
  const parseArrays = config.parseArrays !== false;
  let charset = config.charset === 'iso-8859-1' ? 'iso-8859-1' : 'utf-8';
  let text = String(input == null ? '' : input);

  if (config.ignoreQueryPrefix) text = text.replace(/^\?/, '');
  if (text.length === 0) return {};

  const pieces = limit === Infinity ? text.split(delimiter) : text.split(delimiter, limit);
  const result = {};

  function decode(part) {
    const raw = String(part).replace(/\+/g, ' ');
    if (typeof config.decoder === 'function') {
      return config.decoder(raw, decodeURIComponent, charset, 'value');
    }
    if (charset === 'iso-8859-1') {
      let out = raw.replace(/%([0-9a-f]{2})/gi, function (_, hex) {
        return String.fromCharCode(parseInt(hex, 16));
      });
      return numericEntities ? out.replace(/&#(\d+);/g, function (_, code) {
        return String.fromCharCode(parseInt(code, 10));
      }) : out;
    }
    try {
      return decodeURIComponent(raw);
    } catch (_) {
      return raw;
    }
  }

  function assign(target, key, value) {
    if (Object.prototype.hasOwnProperty.call(target, key)) {
      target[key] = Array.isArray(target[key]) ? target[key].concat(value) : [target[key]].concat(value);
    } else {
      target[key] = value;
    }
  }

  function build(key, value) {
    if (!parseArrays) return { key, value };
    const match = /^(.*)\[\]$/.exec(key);
    if (!match) return { key, value };
    return { key: match[1], value: Array.isArray(value) ? [value] : [value] };
  }

  for (const item of pieces) {
    if (item === '') continue;
    const eq = item.indexOf('=');
    let rawKey = eq < 0 ? item : item.slice(0, eq);
    let rawValue = eq < 0 ? (strictNull ? null : '') : item.slice(eq + 1);

    if (useSentinel && rawKey === 'utf8') {
      if (rawValue === '%E2%9C%93' || rawValue === '✓') charset = 'utf-8';
      if (rawValue === '%26%2310003%3B' || rawValue === '&#10003;') charset = 'iso-8859-1';
      continue;
    }

    const decodedKey = decode(rawKey);
    let decodedValue;
    if (rawValue === null) {
      decodedValue = null;
    } else if (commaArrays && rawValue.indexOf(',') >= 0) {
      decodedValue = rawValue.split(',').map(decode);
    } else {
      decodedValue = decode(rawValue);
    }

    const entry = build(decodedKey, decodedValue);
    assign(result, entry.key, entry.value);
  }

  return result;
}
